#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int arr[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        int maxLen = 0;
        for (int i = 0; i < N; i++) {
            int max = arr[i];
            int secondMax = -1;
            int j = i;
            while (j < N) {
                if (arr[j] > max) {
                    secondMax = max;
                    max = arr[j];
                } else if (arr[j] > secondMax && arr[j] != max) {
                    secondMax = arr[j];
                }
                if (K > max || (K < max && K >= secondMax)) {
                    maxLen = (j - i + 1) > maxLen ? (j - i + 1) : maxLen;
                }
                j++;
            }
        }
        printf("%d\n", maxLen);
    }
    return 0;
}

