        let max = arr[j];
        let secondMax = -1;
        for (let k = j; k < N; k++) {
            if (arr[k] > max) {
                secondMax = max;
                max = arr[k];
            } else if (arr[k] > secondMax && arr[k] != max) {
                secondMax = arr[k];
            }
